// src/hooks/useVaultState.ts
import { useQuery } from "@tanstack/react-query";

// src/utils/vault.ts
import { VAULTS } from "@yo-protocol/core";
function isVaultId(value) {
  return value in VAULTS;
}
function resolveVaultAddress(vault) {
  if (isVaultId(vault)) {
    return VAULTS[vault].address;
  }
  return vault;
}

// src/hooks/useVaultState.ts
function useVaultState(vault, options) {
  const { enabled = true } = options ?? {};
  const client = useYoClient();
  const vaultAddress = resolveVaultAddress(vault);
  const { data, isLoading, isError, error, refetch } = useQuery({
    queryKey: ["yo-vault-state", vaultAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error("Client not available");
      return client.getVaultState(vaultAddress);
    },
    enabled: enabled && !!client,
    staleTime: 3e4,
    refetchInterval: 6e4
  });
  return { vaultState: data, isLoading, isError, error: error ?? null, refetch };
}

